'use client'
import { cn } from '@cascivo/core'
import type { CSSProperties } from 'react'
import styles from './progress-bar.module.css'

export interface ProgressBarProps {
  /** Current value from 0 to max. Omit for an indeterminate bar. */
  value?: number
  max?: number
  label?: string
  helperText?: string
  size?: 'sm' | 'md'
  status?: 'active' | 'success' | 'error'
  className?: string
}

export function ProgressBar({
  value,
  max = 100,
  label,
  helperText,
  size = 'md',
  status = 'active',
  className,
}: ProgressBarProps) {
  const indeterminate = value === undefined
  const clamped = indeterminate ? 0 : Math.min(Math.max(value, 0), max)
  const percent = max > 0 ? (clamped / max) * 100 : 0
  const labelId = label ? `cascade-progress-${label.toLowerCase().replace(/\s+/g, '-')}` : undefined
  const glyph = status === 'success' ? '✓' : status === 'error' ? '✕' : null

  return (
    <div
      data-status={status}
      data-size={size}
      data-state={indeterminate ? 'indeterminate' : undefined}
      className={cn(styles['progress'], className)}
    >
      {label && (
        <span id={labelId} className={styles['label']}>
          {label}
          {glyph && (
            <span className={styles['glyph']} aria-hidden="true">
              {glyph}
            </span>
          )}
        </span>
      )}
      <div
        role="progressbar"
        aria-valuemin={0}
        aria-valuemax={max}
        aria-valuenow={indeterminate ? undefined : clamped}
        aria-labelledby={labelId}
        className={styles['track']}
      >
        <div
          className={styles['fill']}
          style={
            indeterminate
              ? undefined
              : ({ '--cascivo-progress-value': `${percent}%` } as CSSProperties)
          }
        />
      </div>
      {helperText && <span className={styles['helper']}>{helperText}</span>}
    </div>
  )
}

@layer cascivo.component {
  .progress {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    font-family: var(--cascivo-font-sans);

    &[data-status='success'] {
      .fill {
        background-color: var(--cascivo-color-success);
      }

      .glyph {
        color: var(--cascivo-color-success);
      }
    }

    &[data-status='error'] {
      .fill {
        background-color: var(--cascivo-color-destructive);
      }

      .glyph {
        color: var(--cascivo-color-destructive);
      }
    }

    &[data-size='sm'] .track {
      block-size: var(--cascivo-space-1);
    }

    &[data-size='md'] .track {
      block-size: var(--cascivo-space-2);
    }

    &[data-state='indeterminate'] .fill {
      inline-size: 40%;
      transition: none;
      /* Continuous sweep — literal duration; reduced motion slows it below. */
      animation: cascade-progress-sweep 1.4s var(--cascivo-ease-in-out) infinite;
    }
  }

  .label {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-tight);
  }

  .glyph {
    font-size: var(--cascivo-text-xs);
    line-height: 1;
  }

  .track {
    position: relative;
    overflow: hidden;
    inline-size: 100%;
    background-color: var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-full);
  }

  .fill {
    position: absolute;
    inset-block: 0;
    inset-inline-start: 0;
    inline-size: var(--cascivo-progress-value, 0%);
    background-color: var(--cascivo-color-accent);
    border-radius: var(--cascivo-radius-full);
    transition: inline-size var(--cascivo-motion-enter);
  }

  .helper {
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-text-subtle);
    line-height: var(--cascivo-leading-tight);
  }

  @keyframes cascade-progress-sweep {
    from {
      inset-inline-start: -40%;
    }

    to {
      inset-inline-start: 100%;
    }
  }

  @media (prefers-reduced-motion: reduce) {
    .progress[data-state='indeterminate'] .fill {
      animation-duration: 4s;
    }
  }
}
